{"procName":"dbo.tr_dondathang_chitiet_create2","body":"CREATE PROC [dbo].[TR_DONDATHANG_CHITIET_CREATE2]
(
	@maddh nvarchar(200),
	@masp nvarchar(MAX),
	@chitiet nvarchar(MAX),
	@tenchitiet nvarchar(MAX),
	@soluong decimal(18, 3),
	@dvt nvarchar(50),
	@sl_danhan decimal(18, 3),
	@sl_conlai decimal(18, 3),
	@dongia decimal(18, 2),
	@thanhtien decimal(18, 2),
	@loaitien nvarchar(50),
	@donhang nvarchar(MAX),
	@ghichu nvarchar(MAX),
	@hoanthanh_htr bit,
	@create_date datetime,
	@create_by nvarchar(50),
	@update_by nvarchar(50),
	@update_date datetime,
	@active bit,
	@id_maddhmaddh nvarchar(200),
    @dayy float,
    @rong float,
    @dai float,
    @nguyenlieu nvarchar(50),
	@ngaycangiao datetime = null,
    @dongia_m3 float = NULL,
	@fsc_id int = null,
	@tygia decimal(18, 3) = null
)
AS
BEGIN
	IF EXISTS (SELECT 1 FROM tr_dondathang_chitiet WITH(NOLOCK) WHERE maddh = @maddh AND chitiet = @chitiet)
	BEGIN
		UPDATE tr_dondathang_chitiet
		SET soluong = soluong + @soluong,
			sl_danhan = sl_danhan + @sl_danhan,
			sl_conlai = sl_conlai + @sl_conlai,
			thanhtien = thanhtien + @thanhtien,
			update_by = @update_by,
			update_date = @update_date
		WHERE maddh = @maddh AND chitiet = @chitiet
	END
	ELSE
	BEGIN
		INSERT INTO tr_dondathang_chitiet
		(
			maddh,
			masp,
			chitiet,
			tenchitiet,
			soluong,
			dvt,
			sl_danhan,
			sl_conlai,
			dongia,
			thanhtien,
			loaitien,
			donhang,
			ghichu,
			hoanthanh_htr,
			create_date,
			create_by,
			update_by,
			update_date,
			active,
			id_maddhmaddh,
			dayy,
			rong,
			dai,
			nguyenlieu,
			ngaycangiao, 
			dongia_m3,
			fsc_id,
			tygia
		)
		VALUES
		(
			@maddh,
			@masp,
			@chitiet,
			@tenchitiet,
			@soluong,
			@dvt,
			@sl_danhan,
			@sl_conlai,
			@dongia,
			@thanhtien,
			@loaitien,
			@donhang,
			@ghichu,
			@hoanthanh_htr,
			@create_date,
			@create_by,
			@update_by,
			@update_date,
			@active,
			@id_maddhmaddh,
			@dayy,
			@rong,
			@dai,
			@nguyenlieu,
			@ngaycangiao, 
			@dongia_m3,
			@fsc_id,
			@tygia
		)
	END
END
